import React, { useState, useEffect } from 'react';
import { PageHeader, Modal } from '../../components/UI';
import { exerciseService } from '../../services/api';

// ============================================================
// Composant vidéo — key={src} force le rechargement au changement
// ============================================================
function ExerciseVideo({ src, style = {} }) {
  const [error, setError] = useState(false);

  return error ? (
    <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#0d0d0d' }}>
      <div style={{ color: 'var(--text-muted)', fontSize: 12, textAlign: 'center' }}>
        <i className="bi bi-exclamation-circle" style={{ fontSize: 20, display: 'block', marginBottom: 8 }}></i>
        Vidéo indisponible
      </div>
    </div>
  ) : (
    <video
      key={src}
      src={src}
      autoPlay
      loop
      muted
      playsInline
      onError={() => setError(true)}
      style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block', ...style }}
    />
  );
}

export default function Musculation() {
  const [muscles, setMuscles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selected, setSelected] = useState(null);
  const [activeExo, setActiveExo] = useState(null);

  // Récupérer les données depuis l'API
  useEffect(() => {
    const fetchExercises = async () => {
      try {
        setLoading(true);
        const res = await exerciseService.getMuscles();
        setMuscles(res.data.data || []);
        setError(null);
      } catch (err) {
        console.error('Erreur lors du chargement des exercices:', err);
        setError('Erreur lors du chargement des exercices. Veuillez recharger la page.');
      } finally {
        setLoading(false);
      }
    };

    fetchExercises();
  }, []);

  const openMuscle = (m) => { setSelected(m); setActiveExo(null); };
  const displayedVideo = activeExo?.video ?? selected?.video;

  if (loading) {
    return (
      <div style={{ padding: '40px 28px', textAlign: 'center' }}>
        <i className="bi bi-hourglass-split" style={{ fontSize: 32, color: 'var(--text-muted)', animation: 'spin 1s linear infinite' }}></i>
        <div style={{ marginTop: 16, color: 'var(--text-muted)' }}>Chargement des exercices...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div style={{ padding: '40px 28px', textAlign: 'center' }}>
        <i className="bi bi-exclamation-circle" style={{ fontSize: 32, color: 'var(--red)', marginBottom: 12, display: 'block' }}></i>
        <div style={{ color: 'var(--text-muted)' }}>{error}</div>
      </div>
    );
  }

  return (
    <div>
      <PageHeader eyebrow="Guide d'entraînement" title="Exercices par" accent="Groupe Musculaire" />

      <div style={{ padding: '16px 28px 8px', fontSize: 13, color: 'var(--text-muted)' }}>
        Cliquez sur un groupe musculaire pour voir les exercices recommandés, les séries et les conseils techniques.
      </div>

      {/* Grille muscles */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 14, padding: '12px 28px 32px' }}>
        {muscles.map(m => (
          <div key={m.id} className="fz-card hoverable" style={{ overflow: 'hidden', padding: 0 }} onClick={() => openMuscle(m)}>
            <div className="muscle-img-placeholder" style={{ position: 'relative', overflow: 'hidden' }}>
              <ExerciseVideo src={m.video} />
            </div>
            <div style={{ padding: '12px 14px' }}>
              <div style={{ fontFamily: 'var(--font-heading)', fontSize: 16, fontWeight: 700, marginBottom: 2 }}>{m.nom}</div>
              <div style={{ fontSize: 10, color: 'var(--text-dim)', marginBottom: 8 }}>{m.zone} · {m.exercices.length} exercices</div>
              {m.exercices.slice(0, 2).map(e => (
                <div key={e.nom} style={{ fontSize: 11, color: 'var(--text-muted)', marginBottom: 2 }}>
                  <i className="bi bi-chevron-right me-1" style={{ fontSize: 9, color: 'var(--red)' }}></i>{e.nom}
                </div>
              ))}
              <div style={{ fontSize: 10, color: 'var(--text-dim)', marginTop: 4 }}>+{m.exercices.length - 2} autres...</div>
            </div>
          </div>
        ))}
      </div>

      {/* Modale */}
      <Modal show={!!selected} title={selected?.nom} onClose={() => setSelected(null)} size="lg">
        {selected && (
          <div>
            {/* Badges */}
            <div style={{ display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap', alignItems: 'center' }}>
              <span className="fz-badge type">{selected.zone}</span>
              <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>{selected.exercices.length} exercices</span>
              {activeExo && (
                <span
                  onClick={() => setActiveExo(null)}
                  style={{ fontSize: 11, color: 'var(--red)', marginLeft: 'auto', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4 }}
                >
                  <i className="bi bi-arrow-left" style={{ fontSize: 10 }}></i> Groupe musculaire
                </span>
              )}
            </div>

            {/* Vidéo principale */}
            <div style={{ marginBottom: 20, borderRadius: 10, border: '1px solid var(--border)', height: 250, overflow: 'hidden', background: '#0d0d0d', position: 'relative' }}>
              <ExerciseVideo src={displayedVideo} style={{ objectFit: 'contain', background: '#0d0d0d' }} />
              {/* Overlay nom exercice actif */}
              {activeExo && (
                <div style={{
                  position: 'absolute', bottom: 0, left: 0, right: 0,
                  background: 'linear-gradient(transparent, rgba(0,0,0,0.85))',
                  padding: '30px 16px 12px',
                  fontFamily: 'var(--font-heading)', fontSize: 14, fontWeight: 700, color: '#fff',
                  display: 'flex', alignItems: 'center', gap: 8
                }}>
                  <i className="bi bi-play-circle-fill" style={{ color: 'var(--red)', fontSize: 16 }}></i>
                  {activeExo.nom}
                </div>
              )}
            </div>

            {/* Liste exercices cliquables */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              {selected.exercices.map((e) => {
                const isActive = activeExo?.nom === e.nom;
                return (
                  <div
                    key={e.nom}
                    onClick={() => setActiveExo(isActive ? null : e)}
                    style={{
                      background: isActive ? 'rgba(220,38,38,0.08)' : 'var(--surface2)',
                      borderRadius: 10,
                      padding: '14px 16px',
                      borderLeft: `3px solid var(--red)`,
                      cursor: 'pointer',
                      transition: 'all 0.15s ease',
                      outline: isActive ? '1px solid rgba(220,38,38,0.3)' : '1px solid transparent',
                    }}
                  >
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 6 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                        {/* Bouton play/pause */}
                        <div style={{
                          width: 26, height: 26, borderRadius: '50%',
                          background: isActive ? 'var(--red)' : 'rgba(255,255,255,0.06)',
                          border: isActive ? 'none' : '1px solid rgba(255,255,255,0.1)',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          flexShrink: 0, transition: 'all 0.15s'
                        }}>
                          <i
                            className={`bi bi-${isActive ? 'pause-fill' : 'play-fill'}`}
                            style={{ fontSize: 10, color: isActive ? '#fff' : 'var(--red)', marginLeft: isActive ? 0 : 1 }}
                          />
                        </div>
                        <div style={{ fontFamily: 'var(--font-heading)', fontSize: 15, fontWeight: 700, color: isActive ? '#fff' : 'inherit' }}>
                          {e.nom}
                        </div>
                      </div>
                      <span className="fz-badge type">{e.series}</span>
                    </div>
                    <p style={{ fontSize: 12, color: 'var(--text-muted)', margin: 0, lineHeight: 1.6, paddingLeft: 36 }}>
                      {e.desc}
                    </p>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
}
